+type Clause = {
+  patterns: Pattern<unknown>[];
+  predicate?: (value: unknown) => unknown;
+  handler: (selection: unknown, value: unknown) => unknown;
+};
+
+type Operation = Clause | { tap: (result: unknown) => unknown };
+
+/**
+ * Creates a pattern matcher that collects the results of every matching clause.
+ * Call without a value to build a reusable matcher with `.toFunction()`.
+ */
+export function matchEach<const input, output = symbols.unset>(value: input): MatchEach<input, output>;
+export function matchEach<input, output = symbols.unset>(): MatchEach<input, output>;
+export function matchEach(...args: unknown[]): MatchEach<unknown, symbols.unset> {
+  return new MatchEachExpression(args.length > 0, args[0], []) as any;
+}
+
+class MatchEachExpression {
+  constructor(
+    private readonly hasInput: boolean,
+    private readonly input: unknown,
+    private readonly operations: readonly Operation[]
+  ) {}
+
+  with(...args: any[]): MatchEachExpression {
+    const handler = args[args.length - 1] as Clause['handler'];
+    const patterns: Pattern<unknown>[] = [args[0]];
+    let predicate: Clause['predicate'];
+    if (args.length === 3 && typeof args[1] === 'function') predicate = args[1];
+    else if (args.length > 2) patterns.push(...args.slice(1, -1));
+    return this.append({ patterns, predicate, handler });
+  }
+
+  when(predicate: Clause['predicate'], handler: Clause['handler']): MatchEachExpression {
+    return this.append({ patterns: [symbols.matcher], predicate, handler: (_selection, value) => handler(value, value) });
+  }
+
+  tap(callback: (result: unknown) => unknown): MatchEachExpression {
+    return this.append({ tap: callback });
+  }
+
+  otherwise(handler: (value: unknown) => unknown): unknown[] {
+    const results = this.evaluate(this.input);
+    return results.length ? results : [handler(this.input)];
+  }
+
+  exhaustive(handler: (value: unknown) => unknown = defaultCatcher): unknown[] {
+    const results = this.evaluate(this.input);
+    return results.length ? results : [handler(this.input)];
+  }
+
+  run(): unknown[] {
+    return this.exhaustive();
+  }
+
+  returnType(): MatchEachExpression { return this; }
+  narrow(): MatchEachExpression { return this; }
+
+  toFunction(): (input: unknown) => unknown[] {
+    return (input) => {
+      const results = this.evaluate(input);
+      if (!results.length) throw new NonExhaustiveError(input);
+      return results;
+    };
+  }
